// =====================================================
// COST ESTIMATORY TOOL — FULLY REVISED (PRODUCTION SAFE)
// =====================================================


// ===============================
// 1. PROCEDURE DATASET
// ===============================
const procedures = [
  { "name": "Hemorrhoidectomy", "aliases": ["piles","hemorrhoid","fissure","fistula","anal surgery"], "t1": 65000, "t2": 52000, "t3": 39000, "rsi": 300000 },
  { "name": "Coronary Artery Bypass Grafting (CABG)", "aliases": ["cabg","heart bypass","bypass surgery","heart block","open heart"], "t1": 570000, "t2": 456000, "t3": 342000, "rsi": 1000000 },

  {
    "name": "Total Knee Replacement",
    "aliases": [
      "knee surgery",
      "knee replacement",
      "tkr",
      "knee joint",
      "arthritis surgery",
      "total knee arthroplasty"
    ],
    "t1": 285000,
    "t2": 228000,
    "t3": 171000,
    "rsi": 500000
  },

  { "name": "Cataract Surgery", "aliases": ["eye surgery","cataract","lens replacement","motibindu","phaco"], "t1": 57000, "t2": 45600, "t3": 34200, "rsi": 100000 },
  { "name": "Appendectomy", "aliases": ["appendix","appendicitis","appendix removal"], "t1": 68400, "t2": 54720, "t3": 41040, "rsi": 100000 },
  { "name": "Angioplasty", "aliases": ["stent","heart stent","ptca","angio"], "t1": 228000, "t2": 182400, "t3": 136800, "rsi": 300000 },
  { "name": "Hysterectomy", "aliases": ["uterus removal","uterus surgery","womb removal"], "t1": 114000, "t2": 91200, "t3": 68400, "rsi": 200000 },
  { "name": "Total Hip Replacement", "aliases": ["hip replacement","hip surgery","thr","hip joint"], "t1": 342000, "t2": 273600, "t3": 205200, "rsi": 500000 },
  { "name": "Hernia Repair", "aliases": ["hernia","hydrocele","mesh surgery","hernioplasty"], "t1": 57000, "t2": 45600, "t3": 34200, "rsi": 100000 },

  {
    "name": "Cholecystectomy (Gallbladder Removal)",
    "aliases": ["gallbladder","gall bladder","gall bladder removal","gallbladder removal","gall stone","gb stone","cholecystectomy"],
    "t1": 91200, "t2": 72960, "t3": 54720, "rsi": 100000
  },

  { "name": "Prostatectomy", "aliases": ["prostate","prostrate","bph","urology surgery"], "t1": 171000, "t2": 136800, "t3": 102600, "rsi": 200000 },
  { "name": "Cesarean Section", "aliases": ["c-section","c section","delivery surgery","lscs"], "t1": 114000, "t2": 91200, "t3": 68400, "rsi": 200000 },
  { "name": "Kidney Stone Removal", "aliases": ["kidney stone","rirs","lithotripsy","pcnl","stone removal"], "t1": 79800, "t2": 63840, "t3": 47880, "rsi": 100000 },
  { "name": "Liver Transplant", "aliases": ["liver transplant","liver donor","liver failure"], "t1": 2850000, "t2": 2280000, "t3": 1710000, "rsi": 3000000 },
  { "name": "Kidney Transplant", "aliases": ["kidney transplant","renal transplant","kidney failure"], "t1": 1140000, "t2": 912000, "t3": 684000, "rsi": 1500000 },
  { "name": "Heart Valve Replacement", "aliases": ["valve surgery","heart valve","mitral valve","avr","mvr"], "t1": 570000, "t2": 456000, "t3": 342000, "rsi": 1000000 },
  { "name": "Spinal Fusion", "aliases": ["spine surgery","back surgery","slip disc","spinal fusion","vertebra"], "t1": 456000, "t2": 364800, "t3": 273600, "rsi": 500000 },
  { "name": "Mastectomy", "aliases": ["breast removal","breast surgery","mastectomy","breast cancer surgery"], "t1": 228000, "t2": 182400, "t3": 136800, "rsi": 300000 },
  { "name": "Thyroidectomy", "aliases": ["thyroid surgery","thyroid removal","goitre"], "t1": 91200, "t2": 72960, "t3": 54720, "rsi": 100000 },
  { "name": "Tonsillectomy", "aliases": ["tonsils","tonsil removal","throat surgery"], "t1": 45600, "t2": 36480, "t3": 27360, "rsi": 100000 },
  { "name": "Brain Tumor Surgery", "aliases": ["brain surgery","brain tumor","craniotomy","head surgery"], "t1": 570000, "t2": 456000, "t3": 342000, "rsi": 1000000 }
];

const tier1 = ['mumbai','delhi','bangalore','bengaluru','chennai','hyderabad','kolkata','pune','ahmedabad'];
const tier2 = ['jaipur','lucknow','surat','nagpur','chandigarh','coimbatore','indore','kochi','patna'];


// ===============================
// 2. INPUT HANDLING (ROBUST)
// ===============================
let rawInput = "";

if (typeof query === "object" && query !== null) {
  rawInput = query.input || JSON.stringify(query);
} else if (typeof query === "string") {
  rawInput = query;
}

rawInput = rawInput.toLowerCase().trim();

let procedureStr = "";
let cityName = "";

// JSON format
if (rawInput.startsWith("{")) {
  try {
    const parsed = JSON.parse(rawInput);
    procedureStr = (parsed.procedure || "").toLowerCase();
    cityName = (parsed.city || "").toLowerCase();
  } catch {
    procedureStr = rawInput;
  }
}

// Key-value format (supports = and :)
else if (rawInput.includes("procedure") && rawInput.includes("city")) {
  const parts = rawInput.split(";");
  parts.forEach(part => {
    if (part.includes("procedure")) {
      procedureStr = part.split(/[:=]/)[1]?.trim() || "";
    }
    if (part.includes("city")) {
      cityName = part.split(/[:=]/)[1]?.trim() || "";
    }
  });
}

// Semicolon format → "Procedure;City"
else if (rawInput.includes(";")) {
  const parts = rawInput.split(";");
  procedureStr = parts[0].trim();
  cityName = parts[1] ? parts[1].trim() : "";
}

// Comma format → "Procedure,City"
else if (rawInput.includes(",")) {
  const parts = rawInput.split(",");
  procedureStr = parts[0].trim();
  cityName = parts[1] ? parts[1].trim() : "";
}

// Only procedure
else {
  procedureStr = rawInput;
}


// ===============================
// 3. MATCH PROCEDURE
// ===============================
const normalizedProcedure = procedureStr.replace(/\s+/g,"");

const match = procedures.find(p =>
  normalizedProcedure.includes(p.name.toLowerCase().replace(/\s+/g,"")) ||
  p.aliases.some(alias =>
    normalizedProcedure.includes(alias.toLowerCase().replace(/\s+/g,""))
  )
);

if (!match) {
  return `COST ERROR: Procedure not recognized in query: "${procedureStr}".`;
}


// ===============================
// 4. CITY TIER DETECTION
// ===============================
let cost;
let cityInfo;

if (tier1.includes(cityName)) {
  cost = match.t1;
  cityInfo = cityName.charAt(0).toUpperCase() + cityName.slice(1);
}
else if (tier2.includes(cityName)) {
  cost = match.t2;
  cityInfo = cityName.charAt(0).toUpperCase() + cityName.slice(1);
}
else {
  cost = match.t1;
  cityInfo = cityName ? cityName.charAt(0).toUpperCase() + cityName.slice(1) : "Mumbai (Default)";
}


// ===============================
// 5. RETURN OUTPUT
// ===============================
return `RESULTS FOR ${match.name.toUpperCase()}: Market Estimated Cost is ₹${cost.toLocaleString('en-IN')} (based on ${cityInfo}). The recommended Sum Insured for this procedure is ₹${match.rsi.toLocaleString('en-IN')}.`;

// 1. Hunt for numbers in the input
const input = typeof query === 'string' ? query : JSON.stringify(query);
const numbers = input.match(/\d+(\.\d+)?/g);

if (!numbers || numbers.length < 2) {
  return "ERROR: Please provide weight (kg) and height (m) as numbers (e.g., 85, 1.75).";
}

const weight = parseFloat(numbers[0]);
const height = parseFloat(numbers[1]);
const bmi = weight / (height * height);
const cat = (bmi < 18.5) ? "Underweight" : (bmi < 25) ? "Normal" : (bmi < 30) ? "Overweight" : "Obese";

// 2. PROFESSIONAL STRING RETURN (Matching your working cost_estimator)
return `BMI RESULTS: The calculated BMI is ${bmi.toFixed(2)}, which falls into the ${cat} category. (Data used: ${weight}kg, ${height}m).`;

// 1. Capture input properly from n8n tool
const searchTerm = (query || "").toLowerCase().trim();

// 2. Medical Mapping
const medicalMapping = {
  "piles": "Hemorrhoidectomy",
  "fissure": "Sphincterotomy",
  "fistula": "Fistulectomy",
  "kidney stone": "Lithotripsy",
  "cataract": "Phacoemulsification",
  "hernia": "Hernioplasty",
  "appendix": "Appendectomy",
  "gallbladder": "Cholecystectomy",
  "knee replacement": "Total Knee Arthroplasty",
  "joint replacement": "Total Knee Arthroplasty"
};

let foundTechnicalTerm = null;
let foundCommonTerm = null;

// 3. Search for the match
for (const [userTerm, medicalTerm] of Object.entries(medicalMapping)) {
  if (searchTerm.includes(userTerm)) {
    foundTechnicalTerm = medicalTerm;
    // Capitalizes the matched common term (e.g., 'cataract' -> 'Cataract')
    foundCommonTerm = userTerm.charAt(0).toUpperCase() + userTerm.slice(1);
    break;
  }
}

// 4. THE STRING RETURN (Structured for the Agent)
if (foundTechnicalTerm) {
  // Returns a single string with the necessary data
  return `Formal Term: ${foundTechnicalTerm}`;
}
// Already formal
else if (Object.values(medicalMapping).map(v => v.toLowerCase()).includes(searchTerm)) {
  return `Formal Term: ${searchTerm}`;
}
// Fallback
else {
  return `Formal Term: ${searchTerm}`;
}

// 1. ROBUST INPUT HANDLING
let bmiCategory = "";
let procedure = "";

// If agent passed structured object
if (typeof query === 'object' && query !== null) {
    bmiCategory = (query.bmi_category || "").toLowerCase();
    procedure = (query.procedure || "").toLowerCase();
}
// If agent passed string (fallback safety)
else if (typeof query === 'string') {
    const input = query.toLowerCase();
    bmiCategory = input;
    procedure = input;
}

// 2. DEFAULT RISK
let riskLevel = "Low";
let advice = "Standard pre-op protocols apply.";

// 3. BMI-BASED RISK
if (bmiCategory.includes("obese")) {
    riskLevel = "High";
    advice = "Elevated perioperative risk due to obesity. Full cardiac and respiratory evaluation required.";
}
else if (bmiCategory.includes("overweight")) {
    riskLevel = "Moderate";
    advice = "Monitor respiratory and cardiac vitals due to elevated BMI.";
}

// 4. PROCEDURE COMPLEXITY OVERRIDE
const highRiskProcedures = [
    "arthroplasty",
    "cholecystectomy",
    "cabg",
    "bypass",
    "transplant",
    "brain tumor surgery",
    "spinal fusion",
    "heart valve replacement"
];

if (highRiskProcedures.some(p => procedure.includes(p))) {
    riskLevel = "High";
    advice = "Major surgical procedure. Inpatient care recommended; verify ICU availability.";
}

// 5. RETURN STRING (Required by n8n tool contract)
return `RISK ASSESSMENT: The estimated surgical risk is ${riskLevel}. Recommendation: ${advice}`;

// items[0] = webhook form fields, items[1] = extracted PDF text
const raw = items[0].json;
const formData = raw.body ?? raw;   // multipart fields land in .body or root
const pdfData = items[1].json;

return [
  {
    json: {
      full_name:          formData.full_name          ?? null,
      email:              formData.email              ?? null,
      city:               formData.city               ?? null,
      weight:             formData.weight             ?? null,
      height:             formData.height             ?? null,
      planned_procedure:  formData.planned_procedure  ?? null,
      hospital_name:      formData.hospital_name      ?? null,
      policy_text:        pdfData.text                ?? null
    }
  }
];

