const text = $json.output;

// Clean unicode + remove duplicate AI title
const cleaned = text
  .replace(/[^\x00-\x7F]/g, '')
  .replace(/SURGICAL INSURANCE AUDIT REPORT/g, '')
  .trim();

// Build RTF structure
const rtfContent = `
\\rtf1\\ansi\\deff0
{\\fonttbl{\\f0 Arial;}}
\\fs28\\b SURGICAL INSURANCE AUDIT REPORT \\b0\\par
\\par
\\fs24 ${cleaned.replace(/\n/g, '\\par\n')}
`;

return [
  {
    json: {
      formatted: rtfContent
    }
  }
];

